import { useState, useCallback, useRef } from 'react';
import { useAuth } from '../context/SupabaseContext';

type TTSProvider = 'browser' | 'inworld';

interface TTSOptions {
  provider?: TTSProvider;
  rate?: number;
  pitch?: number;
}

export function useTTS() {
  const { invokeEdgeFunction, isPremium } = useAuth();
  const [isSpeaking, setIsSpeaking] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const resolveRef = useRef<(() => void) | null>(null);

  const speak = useCallback(async (text: string, options: TTSOptions = {}) => {
    const provider = options.provider || (isPremium ? 'inworld' : 'browser');
    setIsSpeaking(true);

    if (provider === 'browser') {
      return new Promise<void>((resolve) => {
        // Cancel any ongoing speech
        window.speechSynthesis.cancel();

        const utterance = new SpeechSynthesisUtterance(text);
        utterance.rate = options.rate || 1.0;
        utterance.pitch = options.pitch || 1.0;
        utterance.lang = 'en-US';

        // Try to pick a good voice
        const voices = window.speechSynthesis.getVoices();
        const preferred = voices.find(v =>
          v.name.includes('Google') || v.name.includes('Daniel') || v.name.includes('Alex')
        );
        if (preferred) utterance.voice = preferred;

        utterance.onend = () => { setIsSpeaking(false); resolve(); };
        utterance.onerror = () => { setIsSpeaking(false); resolve(); };

        resolveRef.current = resolve;
        window.speechSynthesis.speak(utterance);
      });
    }

    // Inworld TTS via podcastfy edge function
    try {
      const resp = await invokeEdgeFunction('podcastfy', { text });

      if (resp?.error) {
        // Fallback to browser TTS if Inworld fails
        setIsSpeaking(false);
        return speak(text, { ...options, provider: 'browser' });
      }

      // podcastfy returns raw MP3 bytes — handle as blob
      if (resp instanceof Response) {
        const blob = await resp.blob();
        const url = URL.createObjectURL(blob);
        return new Promise<void>((resolve) => {
          const audio = new Audio(url);
          audioRef.current = audio;
          resolveRef.current = resolve;
          audio.onended = () => {
            setIsSpeaking(false);
            URL.revokeObjectURL(url);
            resolve();
          };
          audio.onerror = () => {
            setIsSpeaking(false);
            URL.revokeObjectURL(url);
            resolve();
          };
          audio.play().catch(() => {
            setIsSpeaking(false);
            resolve();
          });
        });
      }

      // If we got data back as a regular response, try to play it
      setIsSpeaking(false);
    } catch {
      setIsSpeaking(false);
      // Fallback to browser TTS
      return speak(text, { ...options, provider: 'browser' });
    }
  }, [isPremium, invokeEdgeFunction]);

  const stop = useCallback(() => {
    window.speechSynthesis.cancel();
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      audioRef.current = null;
    }
    setIsSpeaking(false);
    if (resolveRef.current) {
      resolveRef.current();
      resolveRef.current = null;
    }
  }, []);

  return { speak, stop, isSpeaking };
}
