import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useGeminiGeneration } from '../hooks/useGeminiGeneration';
import { useTTS } from '../hooks/useTTS';
import { useAchievements } from '../hooks/useAchievements';
import { useToast } from '../components/ui/Toast';
import { RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer } from 'recharts';

type Phase = 'setup' | 'interview' | 'evaluating' | 'review';

interface InterviewQuestion {
  question: string;
  type: string;
  expectedFocus: string;
}

interface AnswerEvaluation {
  score: number;
  relevance: number;
  depth: number;
  structure: number;
  examples: number;
  feedback: string;
  strengths: string[];
  improvements: string[];
}

interface CompletedAnswer {
  question: InterviewQuestion;
  transcript: string;
  evaluation: AnswerEvaluation;
}

// SpeechRecognition types
interface SpeechRecognitionEvent {
  results: { [index: number]: { [index: number]: { transcript: string } }; length: number };
  resultIndex: number;
}

interface SpeechRecognitionInstance {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start: () => void;
  stop: () => void;
  onresult: ((event: SpeechRecognitionEvent) => void) | null;
  onerror: (() => void) | null;
  onend: (() => void) | null;
}

function getSpeechRecognition(): SpeechRecognitionInstance | null {
  const SpeechRecognitionClass = (window as unknown as Record<string, unknown>).SpeechRecognition
    || (window as unknown as Record<string, unknown>).webkitSpeechRecognition;
  if (!SpeechRecognitionClass) return null;
  return new (SpeechRecognitionClass as new () => SpeechRecognitionInstance)();
}

function getLetterGrade(score: number): string {
  if (score >= 9) return 'A+';
  if (score >= 8) return 'A';
  if (score >= 7) return 'B+';
  if (score >= 6) return 'B';
  if (score >= 5) return 'C';
  return 'D';
}

function getGradeColor(score: number): string {
  if (score >= 8) return '#10b981';
  if (score >= 6) return '#f59e0b';
  return '#ef4444';
}

export default function MockInterviewPage() {
  const { user, isPremium, isLoading: authLoading } = useAuth();
  const brand = useBrand();
  const navigate = useNavigate();
  const { generate, isGenerating } = useGeminiGeneration();
  const { speak, stop: stopSpeaking, isSpeaking } = useTTS();
  const { awardBadge } = useAchievements();
  const { showToast } = useToast();

  // Setup state
  const [role, setRole] = useState('');
  const [company, setCompany] = useState('');
  const [interviewType, setInterviewType] = useState('behavioral');
  const [ttsEnabled, setTtsEnabled] = useState(true);
  const [ttsProvider, setTtsProvider] = useState<'browser' | 'inworld'>(isPremium ? 'inworld' : 'browser');

  // Interview state
  const [phase, setPhase] = useState<Phase>('setup');
  const [questions, setQuestions] = useState<InterviewQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [transcript, setTranscript] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [timer, setTimer] = useState(0);
  const [answers, setAnswers] = useState<CompletedAnswer[]>([]);

  // Webcam
  const videoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const recognitionRef = useRef<SpeechRecognitionInstance | null>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const speechSupported = typeof window !== 'undefined' && !!(
    (window as unknown as Record<string, unknown>).SpeechRecognition ||
    (window as unknown as Record<string, unknown>).webkitSpeechRecognition
  );

  useEffect(() => {
    if (!authLoading && !user) navigate('/login');
    if (!authLoading && user && !isPremium) navigate('/pricing');
  }, [authLoading, user, isPremium, navigate]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(t => t.stop());
      }
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  // Timer
  useEffect(() => {
    if (phase === 'interview') {
      timerRef.current = setInterval(() => setTimer(t => t + 1), 1000);
    } else if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [phase]);

  const formatTime = (s: number) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  async function startInterview() {
    if (!role.trim()) { showToast('Please enter a job role.', true); return; }

    // Request webcam
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch {
      showToast('Camera access denied. You can still type your answers.', true);
    }

    // Generate questions
    const systemPrompt = `You are an expert interviewer. Generate exactly 5 interview questions for the given role and type.

CRITICAL: Respond with ONLY a \`\`\`json code block containing a JSON array:
[
  { "question": "Tell me about a time...", "type": "behavioral", "expectedFocus": "Leadership, teamwork" }
]

Make questions specific to the role and company. Mix difficulty levels.`;

    const userPrompt = `Role: ${role}\nCompany: ${company || 'General'}\nType: ${interviewType}`;
    const result = await generate({ systemPrompt, userPrompt, timeout: 30000 });

    if (result?.rawText) {
      try {
        const jsonMatch = result.rawText.match(/```json\s*([\s\S]*?)```/) || result.rawText.match(/```\s*([\s\S]*?)```/);
        const parsed = JSON.parse(jsonMatch ? jsonMatch[1] : result.rawText) as InterviewQuestion[];
        setQuestions(parsed);
        setPhase('interview');
        setCurrentIdx(0);
        setTimer(0);
        // Speak the first question
        if (ttsEnabled && parsed.length > 0) {
          speak(parsed[0].question, { provider: ttsProvider }).then(() => {
            if (speechSupported) startListening();
          });
        }
      } catch {
        showToast('Failed to generate questions. Please try again.', true);
      }
    }
  }

  const startListening = useCallback(() => {
    if (!speechSupported) return;
    const recognition = getSpeechRecognition();
    if (!recognition) return;

    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onresult = (event: SpeechRecognitionEvent) => {
      let finalTranscript = '';
      for (let i = event.resultIndex; i < event.results.length; i++) {
        finalTranscript += event.results[i][0].transcript;
      }
      setTranscript(prev => prev + ' ' + finalTranscript);
    };

    recognition.onerror = () => { setIsListening(false); };
    recognition.onend = () => { setIsListening(false); };

    recognition.start();
    recognitionRef.current = recognition;
    setIsListening(true);
  }, [speechSupported]);

  const stopListening = useCallback(() => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
    setIsListening(false);
  }, []);

  async function submitAnswer() {
    if (!transcript.trim()) { showToast('Please provide an answer first.', true); return; }
    stopListening();
    setPhase('evaluating');

    const currentQ = questions[currentIdx];
    const systemPrompt = `You are an interview coach. Evaluate the candidate's answer to the interview question.

CRITICAL: Respond with ONLY a \`\`\`json code block:
{
  "score": 7,
  "relevance": 8,
  "depth": 6,
  "structure": 7,
  "examples": 5,
  "feedback": "Your answer showed...",
  "strengths": ["Good use of STAR method", "Specific metrics"],
  "improvements": ["Could add more detail about outcome"]
}

Scores are 1-10. Be constructive but honest.`;

    const userPrompt = `Question: ${currentQ.question}\nExpected Focus: ${currentQ.expectedFocus}\n\nCandidate's Answer:\n${transcript}`;
    const result = await generate({ systemPrompt, userPrompt, timeout: 30000 });

    let evaluation: AnswerEvaluation = {
      score: 5, relevance: 5, depth: 5, structure: 5, examples: 5,
      feedback: 'Evaluation not available.', strengths: [], improvements: [],
    };

    if (result?.rawText) {
      try {
        const jsonMatch = result.rawText.match(/```json\s*([\s\S]*?)```/) || result.rawText.match(/```\s*([\s\S]*?)```/);
        evaluation = JSON.parse(jsonMatch ? jsonMatch[1] : result.rawText) as AnswerEvaluation;
      } catch { /* use defaults */ }
    }

    const completed: CompletedAnswer = { question: currentQ, transcript: transcript.trim(), evaluation };
    setAnswers(prev => [...prev, completed]);

    if (currentIdx < questions.length - 1) {
      const nextIdx = currentIdx + 1;
      setCurrentIdx(nextIdx);
      setTranscript('');
      setPhase('interview');
      // Speak the next question
      if (ttsEnabled) {
        speak(questions[nextIdx].question, { provider: ttsProvider }).then(() => {
          if (speechSupported) startListening();
        });
      }
    } else {
      // End of interview
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(t => t.stop());
      }
      setPhase('review');

      // Award badges
      awardBadge('interview_ready');
      const allAnswers = [...answers, completed];
      const avg = allAnswers.reduce((s, a) => s + a.evaluation.score, 0) / allAnswers.length;
      if (avg >= 9) awardBadge('mock_master');
    }
  }

  if (authLoading) return null;

  // Review phase data
  const avgScore = answers.length > 0 ? answers.reduce((s, a) => s + a.evaluation.score, 0) / answers.length : 0;
  const radarData = answers.length > 0 ? [
    { dimension: 'Relevance', value: answers.reduce((s, a) => s + a.evaluation.relevance, 0) / answers.length },
    { dimension: 'Depth', value: answers.reduce((s, a) => s + a.evaluation.depth, 0) / answers.length },
    { dimension: 'Structure', value: answers.reduce((s, a) => s + a.evaluation.structure, 0) / answers.length },
    { dimension: 'Examples', value: answers.reduce((s, a) => s + a.evaluation.examples, 0) / answers.length },
    { dimension: 'Overall', value: avgScore },
  ] : [];

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
        <div style={{ width: '48px', height: '48px', borderRadius: '2px', background: brand.primaryColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '1.2rem' }}>
          <i className="fa-solid fa-video" />
        </div>
        <div>
          <h1 style={{ fontSize: '1.5rem', margin: 0, color: 'var(--text-primary)' }}>Mock Interview</h1>
          <p style={{ margin: 0, fontSize: '0.82rem', color: 'var(--text-secondary)' }}>Practice on camera with AI scoring and real-time feedback</p>
        </div>
      </div>

      {/* Setup Phase */}
      {phase === 'setup' && (
        <div className="glass-panel" style={{ padding: '1.5rem' }}>
          <h2 style={{ fontSize: '1.1rem', margin: '0 0 1.25rem', color: 'var(--text-primary)' }}>Interview Setup</h2>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
            <div>
              <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>Target Role *</label>
              <input value={role} onChange={e => setRole(e.target.value)} placeholder="e.g., Senior Software Engineer" style={{ width: '100%' }} />
            </div>
            <div>
              <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>Company (optional)</label>
              <input value={company} onChange={e => setCompany(e.target.value)} placeholder="e.g., Google, Stripe" style={{ width: '100%' }} />
            </div>
          </div>

          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>Interview Type</label>
            <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
              {[
                { key: 'behavioral', label: 'Behavioral', icon: 'fa-brain' },
                { key: 'technical', label: 'Technical', icon: 'fa-code' },
                { key: 'leadership', label: 'Leadership', icon: 'fa-users-gear' },
                { key: 'mixed', label: 'Mixed', icon: 'fa-shuffle' },
              ].map(t => (
                <button
                  key={t.key}
                  onClick={() => setInterviewType(t.key)}
                  className="btn"
                  style={{
                    padding: '0.5rem 1rem',
                    border: `1px dashed ${interviewType === t.key ? brand.primaryColor : 'var(--panel-border)'}`,
                    background: interviewType === t.key ? `${brand.primaryColor}15` : 'transparent',
                    color: interviewType === t.key ? brand.primaryColor : 'var(--text-secondary)',
                    cursor: 'pointer',
                    fontSize: '0.82rem',
                    fontWeight: 500,
                  }}
                >
                  <i className={`fa-solid ${t.icon}`} style={{ marginRight: '0.3rem' }} /> {t.label}
                </button>
              ))}
            </div>
          </div>

          {/* TTS Controls */}
          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.82rem', color: 'var(--text-primary)' }}>
              <input type="checkbox" checked={ttsEnabled} onChange={e => setTtsEnabled(e.target.checked)} />
              <i className="fa-solid fa-volume-high" style={{ color: ttsEnabled ? brand.primaryColor : 'var(--text-secondary)' }} />
              AI reads questions aloud
            </label>
            {ttsEnabled && isPremium && (
              <div style={{ marginTop: '0.5rem', marginLeft: '1.5rem', display: 'flex', gap: '0.5rem' }}>
                {(['browser', 'inworld'] as const).map(p => (
                  <button
                    key={p}
                    onClick={() => setTtsProvider(p)}
                    className="btn"
                    style={{
                      padding: '0.35rem 0.75rem',
                      border: `1px dashed ${ttsProvider === p ? brand.primaryColor : 'var(--panel-border)'}`,
                      background: ttsProvider === p ? `${brand.primaryColor}15` : 'transparent',
                      color: ttsProvider === p ? brand.primaryColor : 'var(--text-secondary)',
                      cursor: 'pointer',
                      fontSize: '0.75rem',
                      fontWeight: 500,
                    }}
                  >
                    {p === 'browser' ? 'Browser Voice' : 'Premium Voice'}
                  </button>
                ))}
              </div>
            )}
          </div>

          {!speechSupported && (
            <div style={{ background: 'rgba(245,158,11,0.08)', border: '1px dashed rgba(245,158,11,0.2)', borderRadius: '2px', padding: '0.6rem 0.75rem', marginBottom: '1rem', fontSize: '0.78rem', color: '#f59e0b' }}>
              <i className="fa-solid fa-triangle-exclamation" /> Speech recognition not supported in this browser. You can type your answers instead.
            </div>
          )}

          <button
            onClick={startInterview}
            disabled={isGenerating}
            className="btn secondary-btn"
            style={{ width: '100%', padding: '0.85rem', fontSize: '1rem', cursor: isGenerating ? 'not-allowed' : 'pointer' }}
          >
            {isGenerating ? <><i className="fa-solid fa-spinner fa-spin" /> Preparing questions...</> : <><i className="fa-solid fa-play" /> Start Interview</>}
          </button>
        </div>
      )}

      {/* Interview Phase */}
      {(phase === 'interview' || phase === 'evaluating') && questions.length > 0 && (
        <div>
          {/* Progress + Timer */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>
              Question {currentIdx + 1} of {questions.length}
            </span>
            <span style={{ fontSize: '0.82rem', fontWeight: 600, color: 'var(--text-primary)', fontFamily: "'JetBrains Mono', monospace" }}>
              <i className="fa-solid fa-clock" style={{ marginRight: '0.3rem' }} /> {formatTime(timer)}
            </span>
          </div>

          {/* Progress bar */}
          <div style={{ height: '4px', background: 'var(--panel-border)', borderRadius: '2px', marginBottom: '1.5rem' }}>
            <div style={{ height: '100%', width: `${((currentIdx + 1) / questions.length) * 100}%`, background: brand.primaryColor, borderRadius: '2px', transition: 'width 0.3s' }} />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
            {/* Webcam */}
            <div style={{ background: '#000', borderRadius: '2px', overflow: 'hidden', aspectRatio: '4/3', position: 'relative' }}>
              <video ref={videoRef} autoPlay muted playsInline style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)' }} />
              {isListening && (
                <div style={{ position: 'absolute', bottom: '0.75rem', left: '50%', transform: 'translateX(-50%)', background: 'rgba(239,68,68,0.9)', color: '#fff', padding: '0.3rem 0.75rem', borderRadius: '2px', fontSize: '0.72rem', fontWeight: 600 }}>
                  <i className="fa-solid fa-microphone fa-beat" /> Recording...
                </div>
              )}
            </div>

            {/* Question + Answer */}
            <div>
              {/* Speaking indicator */}
              {isSpeaking && (
                <div style={{
                  display: 'flex', alignItems: 'center', gap: '0.5rem',
                  color: brand.primaryColor, fontSize: '0.78rem', marginBottom: '0.5rem',
                  fontWeight: 600,
                }}>
                  <i className="fa-solid fa-volume-high fa-beat" />
                  AI Interviewer is speaking...
                </div>
              )}

              {/* Question */}
              <div style={{ background: `${brand.primaryColor}10`, border: `1px dashed ${brand.primaryColor}30`, borderRadius: '2px', padding: '1rem', marginBottom: '1rem' }}>
                <div style={{ fontSize: '0.7rem', fontWeight: 600, color: brand.primaryColor, marginBottom: '0.4rem', textTransform: 'uppercase' }}>
                  {questions[currentIdx].type}
                </div>
                <p style={{ fontSize: '1rem', fontWeight: 600, color: 'var(--text-primary)', margin: 0, lineHeight: 1.5 }}>
                  {questions[currentIdx].question}
                </p>
              </div>

              {/* Transcript / Text Input */}
              <textarea
                value={transcript}
                onChange={e => setTranscript(e.target.value)}
                placeholder={speechSupported ? 'Your answer will appear here as you speak, or type manually...' : 'Type your answer here...'}
                rows={6}
                disabled={phase === 'evaluating'}
                style={{ width: '100%', resize: 'vertical', marginBottom: '0.75rem' }}
              />

              {/* Controls */}
              <div style={{ display: 'flex', gap: '0.5rem' }}>
                {isSpeaking && (
                  <button
                    onClick={() => { stopSpeaking(); if (speechSupported) startListening(); }}
                    className="btn ghost-btn"
                    style={{ padding: '0.6rem 1rem', fontSize: '0.82rem', cursor: 'pointer' }}
                  >
                    <i className="fa-solid fa-forward" /> Skip
                  </button>
                )}
                {speechSupported && (
                  <button
                    onClick={isListening ? stopListening : startListening}
                    disabled={phase === 'evaluating'}
                    className="btn ghost-btn"
                    style={{
                      padding: '0.6rem 1rem',
                      background: isListening ? '#ef4444' : 'var(--panel-bg)',
                      color: isListening ? '#fff' : 'var(--text-primary)',
                      cursor: 'pointer',
                      fontSize: '0.82rem',
                      fontWeight: 600,
                    }}
                  >
                    <i className={`fa-solid ${isListening ? 'fa-stop' : 'fa-microphone'}`} />
                    {isListening ? ' Stop' : ' Speak'}
                  </button>
                )}

                <button
                  onClick={submitAnswer}
                  disabled={phase === 'evaluating' || !transcript.trim()}
                  className="btn secondary-btn"
                  style={{
                    flex: 1,
                    padding: '0.6rem',
                    fontSize: '0.85rem',
                    cursor: phase === 'evaluating' ? 'not-allowed' : 'pointer',
                  }}
                >
                  {phase === 'evaluating' ? <><i className="fa-solid fa-spinner fa-spin" /> Evaluating...</> : <><i className="fa-solid fa-paper-plane" /> Submit Answer</>}
                </button>
              </div>
            </div>
          </div>

          {/* Previous answers feedback */}
          {answers.length > 0 && (
            <div style={{ marginTop: '1.5rem' }}>
              <h4 style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: '0.5rem' }}>Previous Feedback</h4>
              {answers.slice(-1).map((a, i) => (
                <div key={i} className="glass-panel" style={{ padding: '1rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
                    <span style={{ fontSize: '0.78rem', color: 'var(--text-secondary)' }}>Q{answers.length}: {a.question.question.substring(0, 60)}...</span>
                    <span style={{ fontSize: '1rem', fontWeight: 800, color: getGradeColor(a.evaluation.score) }}>{a.evaluation.score}/10</span>
                  </div>
                  <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', margin: 0 }}>{a.evaluation.feedback}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Review Phase */}
      {phase === 'review' && answers.length > 0 && (
        <div>
          {/* Overall Score */}
          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
            <div style={{ fontSize: '4rem', fontWeight: 800, color: getGradeColor(avgScore) }}>
              {getLetterGrade(avgScore)}
            </div>
            <div style={{ fontSize: '1.2rem', fontWeight: 600, color: 'var(--text-primary)' }}>
              {avgScore.toFixed(1)} / 10 Overall
            </div>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem' }}>
              {answers.length} questions answered in {formatTime(timer)}
            </p>
          </div>

          {/* Radar Chart */}
          <div className="glass-panel" style={{ padding: '1.25rem', marginBottom: '1.5rem' }}>
            <h3 style={{ fontSize: '0.9rem', margin: '0 0 0.5rem', color: 'var(--text-primary)', textAlign: 'center' }}>Performance Breakdown</h3>
            <ResponsiveContainer width="100%" height={300}>
              <RadarChart data={radarData}>
                <PolarGrid stroke="var(--panel-border)" />
                <PolarAngleAxis dataKey="dimension" tick={{ fill: 'var(--text-secondary)', fontSize: 12 }} />
                <PolarRadiusAxis domain={[0, 10]} tick={{ fill: 'var(--text-secondary)', fontSize: 10 }} />
                <Radar dataKey="value" stroke={brand.primaryColor} fill={brand.primaryColor} fillOpacity={0.3} />
              </RadarChart>
            </ResponsiveContainer>
          </div>

          {/* Per-question Scorecard */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem', marginBottom: '1.5rem' }}>
            {answers.map((a, i) => (
              <div key={i} className="glass-panel" style={{ padding: '1.25rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.75rem' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: '0.7rem', fontWeight: 600, color: brand.primaryColor, textTransform: 'uppercase', marginBottom: '0.2rem' }}>
                      Q{i + 1} — {a.question.type}
                    </div>
                    <p style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-primary)', margin: 0 }}>
                      {a.question.question}
                    </p>
                  </div>
                  <div style={{ textAlign: 'center', marginLeft: '1rem' }}>
                    <div style={{ fontSize: '1.5rem', fontWeight: 800, color: getGradeColor(a.evaluation.score) }}>
                      {a.evaluation.score}
                    </div>
                    <div style={{ fontSize: '0.65rem', color: 'var(--text-secondary)' }}>/10</div>
                  </div>
                </div>

                <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', margin: '0 0 0.75rem', lineHeight: 1.5 }}>
                  {a.evaluation.feedback}
                </p>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                  {a.evaluation.strengths.length > 0 && (
                    <div>
                      <div style={{ fontSize: '0.72rem', fontWeight: 600, color: '#10b981', marginBottom: '0.3rem' }}>Strengths</div>
                      {a.evaluation.strengths.map((s, j) => (
                        <div key={j} style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.2rem' }}>
                          <i className="fa-solid fa-check" style={{ color: '#10b981', marginRight: '0.3rem', fontSize: '0.65rem' }} />{s}
                        </div>
                      ))}
                    </div>
                  )}
                  {a.evaluation.improvements.length > 0 && (
                    <div>
                      <div style={{ fontSize: '0.72rem', fontWeight: 600, color: '#f59e0b', marginBottom: '0.3rem' }}>Improve</div>
                      {a.evaluation.improvements.map((s, j) => (
                        <div key={j} style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: '0.2rem' }}>
                          <i className="fa-solid fa-arrow-up" style={{ color: '#f59e0b', marginRight: '0.3rem', fontSize: '0.65rem' }} />{s}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>

          {/* Try Again */}
          <button
            onClick={() => {
              setPhase('setup');
              setQuestions([]);
              setAnswers([]);
              setCurrentIdx(0);
              setTranscript('');
              setTimer(0);
            }}
            className="btn secondary-btn"
            style={{ width: '100%', padding: '0.75rem', fontSize: '0.95rem', cursor: 'pointer' }}
          >
            <i className="fa-solid fa-rotate" /> Practice Again
          </button>
        </div>
      )}
    </div>
  );
}
